// ---- Sealed class for state management ----
sealed class Result<out T> {
    data class Success<T>(val data: T) : Result<T>()
    data class Error(val message: String) : Result<Nothing>()
    object Loading : Result<Nothing>()
}

// ---- Sealed class for UI events ----
sealed class UIEvent {
    data class ButtonClick(val id: Int) : UIEvent()
    data class TextInput(val text: String) : UIEvent()
    object Refresh : UIEvent()
    data class Navigation(val route: String) : UIEvent()
}

// ---- Sealed class for network responses ----
sealed class NetworkResponse {
    data class Success(val data: String) : NetworkResponse()
    data class Failure(val code: Int, val message: String) : NetworkResponse()
    object Loading : NetworkResponse()
}

// ---- Sealed class with helper methods ----
sealed class Shape {
    data class Circle(val radius: Double) : Shape()
    data class Rectangle(val width: Double, val height: Double) : Shape()
    object Unknown : Shape()

    fun area(): Double = when (this) {
        is Circle -> Math.PI * radius * radius
        is Rectangle -> width * height
        is Unknown -> 0.0
    }

    fun perimeter(): Double = when (this) {
        is Circle -> 2 * Math.PI * radius
        is Rectangle -> 2 * (width + height)
        is Unknown -> 0.0
    }
}

// ---- Sealed class for authentication states ----
sealed class AuthState {
    object Unauthenticated : AuthState()
    object Authenticating : AuthState()
    data class Authenticated(val user: String) : AuthState()
    data class Error(val message: String) : AuthState()
}

fun main() {
    // ---- Result states ----
    val success: Result<String> = Result.Success("Data loaded")
    val error: Result<Nothing> = Result.Error("Network failure")
    val loading: Result<Nothing> = Result.Loading

    fun processResult(result: Result<String>) {
        when (result) {
            is Result.Success -> println("Success: ${result.data}")
            is Result.Error -> println("Error: ${result.message}")
            is Result.Loading -> println("Loading...")
        }
    }

    processResult(success)
    processResult(error)
    processResult(loading)

    // ---- UI events ----
    val events = listOf(
        UIEvent.ButtonClick(1),
        UIEvent.TextInput("Hello"),
        UIEvent.Refresh,
        UIEvent.Navigation("/home")
    )

    for (event in events) {
        when (event) {
            is UIEvent.ButtonClick -> println("Button clicked: ${event.id}")
            is UIEvent.TextInput -> println("Text input: ${event.text}")
            is UIEvent.Refresh -> println("Refreshing...")
            is UIEvent.Navigation -> println("Navigate to: ${event.route}")
        }
    }

    // ---- Shape with methods ----
    val circle = Shape.Circle(5.0)
    val rectangle = Shape.Rectangle(4.0, 6.0)
    val unknown = Shape.Unknown

    val shapes = listOf(circle, rectangle, unknown)
    for (shape in shapes) {
        println("${shape::class.simpleName}: Area=${shape.area()}, Perimeter=${shape.perimeter()}")
    }

    // ---- Auth states ----
    val authStates = listOf(
        AuthState.Unauthenticated,
        AuthState.Authenticating,
        AuthState.Authenticated("Alice"),
        AuthState.Error("Invalid credentials")
    )

    for (state in authStates) {
        when (state) {
            AuthState.Unauthenticated -> println("Not logged in")
            AuthState.Authenticating -> println("Logging in...")
            is AuthState.Authenticated -> println("Welcome, ${state.user}!")
            is AuthState.Error -> println("Error: ${state.message}")
        }
    }
}

